#!/usr/bin/env bash
# Homelab v3.2 - BacsCloud branding for Nextcloud
# Run this on the Proxmox host as root, normally: root@192.168.50.100
# Target: VM104 / 192.168.50.104, Docker container: hb-nextcloud
#
# Usage:
#   bash 30-apply-bacscloud-nextcloud-branding.sh apply
#   bash 30-apply-bacscloud-nextcloud-branding.sh status
#   bash 30-apply-bacscloud-nextcloud-branding.sh restore-default
#
# Optional overrides:
#   NEXTCLOUD_IP=192.168.50.104
#   NEXTCLOUD_SSH_USER=bacmaster
#   NEXTCLOUD_SSH_PASS='password-if-no-key'
#   NEXTCLOUD_CONTAINER=hb-nextcloud
#
# This script uses Nextcloud's supported theming app through occ.
# It does NOT edit Nextcloud core files.

set -Eeuo pipefail

MODE="${1:-apply}"
VM_IP="${NEXTCLOUD_IP:-${BACSCLOUD_IP:-192.168.50.104}}"
BRAND_NAME="${BRAND_NAME:-BacsCloud}"
BRAND_SLOGAN="${BRAND_SLOGAN:-Your data. Your control.}"
BRAND_URL="${BRAND_URL:-https://cloud.bacmastercloud.com}"
BRAND_COLOR="${BRAND_COLOR:-#008CFF}"
PREFERRED_CONTAINER="${NEXTCLOUD_CONTAINER:-hb-nextcloud}"
REMOTE_ASSET_DIR="/tmp/bacscloud-nextcloud-branding-assets"
LOCAL_WORKDIR="/tmp/bacscloud-nextcloud-branding-assets-$$"
LOG_DIR="/root/homelab-logs"
LOG_FILE="$LOG_DIR/bacscloud-nextcloud-branding-$(date +%Y%m%d-%H%M%S).log"

mkdir -p "$LOG_DIR"
exec > >(tee -a "$LOG_FILE") 2>&1

say() { printf '\n==> %s\n' "$*"; }
ok() { printf 'OK: %s\n' "$*"; }
warn() { printf 'WARN: %s\n' "$*"; }
fail() { printf 'ERROR: %s\n' "$*"; exit 1; }

case "$MODE" in
  apply|status|restore-default) ;;
  *)
    cat <<USAGE
Usage:
  bash $0 apply
  bash $0 status
  bash $0 restore-default
USAGE
    exit 2
    ;;
esac

if [[ "${EUID:-$(id -u)}" -ne 0 ]]; then
  fail "This script must be run on the Proxmox host as root. Example: ssh root@192.168.50.100"
fi

say "Homelab v3.2 - BacsCloud Nextcloud branding"
printf 'Mode: %s\nTarget VM: %s\nPreferred container: %s\nLog: %s\n' "$MODE" "$VM_IP" "$PREFERRED_CONTAINER" "$LOG_FILE"

# Load Homelab env files if available. Missing files are fine.
for env_file in \
  /root/homelab-secrets/global.env \
  /root/homelab-secrets/users.env \
  /root/homelab-secrets/nextcloud.env \
  /root/homelab-secrets/bacscloud.env; do
  if [[ -f "$env_file" ]]; then
    set +u
    # shellcheck disable=SC1090
    source "$env_file" || true
    set -u
  fi
done

# Choose SSH user. Key auth is preferred. Password auth is optional if sshpass exists.
ENV_SSH_USER="${NEXTCLOUD_SSH_USER:-${VM104_SSH_USER:-${HOMELAB_ADMIN_USER:-${ADMIN_USER:-${BACMASTER_USER:-}}}}}"
SSH_PASS="${NEXTCLOUD_SSH_PASS:-${VM104_SSH_PASS:-${HOMELAB_ADMIN_PASS:-${ADMIN_PASS:-${BACMASTER_PASS:-${BACMASTER_PASSWORD:-}}}}}}"
SSH_OPTS=(
  -o StrictHostKeyChecking=accept-new
  -o UserKnownHostsFile=/root/.ssh/known_hosts
  -o ConnectTimeout=10
  -o ServerAliveInterval=15
  -o ServerAliveCountMax=4
)
SSH_USER=""
SSH_MODE="key"

unique_candidates() {
  local seen="" candidate
  for candidate in "$@"; do
    [[ -n "$candidate" ]] || continue
    case " $seen " in *" $candidate "*) continue ;; esac
    seen+=" $candidate"
    printf '%s\n' "$candidate"
  done
}

try_key_user() {
  local u="$1"
  ssh "${SSH_OPTS[@]}" -o BatchMode=yes "$u@$VM_IP" "printf SSH_OK" >/tmp/bacscloud-ssh-test.$$ 2>/dev/null || return 1
  grep -q "SSH_OK" /tmp/bacscloud-ssh-test.$$
}

say "Checking SSH access to VM104"
while IFS= read -r candidate; do
  if try_key_user "$candidate"; then
    SSH_USER="$candidate"
    SSH_MODE="key"
    ok "SSH key connection OK: $SSH_USER@$VM_IP"
    break
  fi
done < <(unique_candidates "$ENV_SSH_USER" bacmaster root)
rm -f /tmp/bacscloud-ssh-test.$$ 2>/dev/null || true

if [[ -z "$SSH_USER" ]]; then
  if [[ -n "$SSH_PASS" ]]; then
    command -v sshpass >/dev/null 2>&1 || fail "SSH key failed and NEXTCLOUD_SSH_PASS is set, but sshpass is not installed on Proxmox. Either install sshpass or set up SSH key auth to VM104."
    while IFS= read -r candidate; do
      if sshpass -p "$SSH_PASS" ssh "${SSH_OPTS[@]}" "$candidate@$VM_IP" "printf SSH_OK" >/tmp/bacscloud-ssh-test.$$ 2>/dev/null && grep -q "SSH_OK" /tmp/bacscloud-ssh-test.$$; then
        SSH_USER="$candidate"
        SSH_MODE="pass"
        ok "SSH password connection OK: $SSH_USER@$VM_IP"
        break
      fi
    done < <(unique_candidates "$ENV_SSH_USER" bacmaster root)
    rm -f /tmp/bacscloud-ssh-test.$$ 2>/dev/null || true
  fi
fi

[[ -n "$SSH_USER" ]] || fail "Could not connect to VM104 via SSH. Expected key auth for bacmaster@${VM_IP} or root@${VM_IP}."

remote_plain() {
  local cmd="$1"
  if [[ "$SSH_MODE" == "pass" ]]; then
    sshpass -p "$SSH_PASS" ssh "${SSH_OPTS[@]}" "$SSH_USER@$VM_IP" "$cmd"
  else
    ssh "${SSH_OPTS[@]}" "$SSH_USER@$VM_IP" "$cmd"
  fi
}

remote_copy_file() {
  local src="$1"
  local dst="$2"
  if [[ "$SSH_MODE" == "pass" ]]; then
    sshpass -p "$SSH_PASS" scp "${SSH_OPTS[@]}" "$src" "$SSH_USER@$VM_IP:$dst"
  else
    scp "${SSH_OPTS[@]}" "$src" "$SSH_USER@$VM_IP:$dst"
  fi
}

remote_sudo_bash() {
  local script="$1"
  if [[ "$SSH_USER" == "root" ]]; then
    if [[ "$SSH_MODE" == "pass" ]]; then
      printf '%s' "$script" | sshpass -p "$SSH_PASS" ssh "${SSH_OPTS[@]}" "$SSH_USER@$VM_IP" "bash -s"
    else
      printf '%s' "$script" | ssh "${SSH_OPTS[@]}" "$SSH_USER@$VM_IP" "bash -s"
    fi
  else
    if [[ "$SSH_MODE" == "pass" && -n "$SSH_PASS" ]]; then
      { printf '%s\n' "$SSH_PASS"; printf '%s' "$script"; } | sshpass -p "$SSH_PASS" ssh "${SSH_OPTS[@]}" "$SSH_USER@$VM_IP" "sudo -S -p '' bash -s"
    else
      printf '%s' "$script" | ssh "${SSH_OPTS[@]}" "$SSH_USER@$VM_IP" "sudo -n bash -s"
    fi
  fi
}

