ASSET_BACSCLOUD_BACKGROUND
  base64 -d "$LOCAL_WORKDIR/bacscloud-login-background-safe-2560x1440.png.b64" > "$LOCAL_WORKDIR/bacscloud-login-background-safe-2560x1440.png"

  rm -f "$LOCAL_WORKDIR"/*.b64
}

find_asset_dir() {
  local script_dir=""
  script_dir="$(cd -- "$(dirname -- "${BASH_SOURCE[0]}")" && pwd -P)"
  if [[ -f "$script_dir/assets/bacscloud-logo-transparent.png" && \
        -f "$script_dir/assets/bacscloud-favicon-transparent.png" && \
        -f "$script_dir/assets/bacscloud-login-background-safe-2560x1440.png" ]]; then
    printf '%s\n' "$script_dir/assets"
    return 0
  fi

  if [[ -f "$script_dir/bacscloud-logo-transparent.png" && \
        -f "$script_dir/bacscloud-favicon-transparent.png" && \
        -f "$script_dir/bacscloud-login-background-safe-2560x1440.png" ]]; then
    printf '%s\n' "$script_dir"
    return 0
  fi

  write_embedded_assets
  printf '%s\n' "$LOCAL_WORKDIR"
}

cleanup() {
  rm -rf "$LOCAL_WORKDIR" 2>/dev/null || true
}
trap cleanup EXIT

ASSET_DIR="$(find_asset_dir)"

if [[ "$MODE" == "apply" ]]; then
  say "Preparing BacsCloud branding assets"
  for f in \
    bacscloud-logo-transparent.png \
    bacscloud-favicon-transparent.png \
    bacscloud-login-background-safe-2560x1440.png; do
    [[ -s "$ASSET_DIR/$f" ]] || fail "Missing asset: $ASSET_DIR/$f"
    ok "Asset ready: $f"
  done

  say "Copying assets to VM104"
  remote_plain "rm -rf '$REMOTE_ASSET_DIR' && mkdir -p '$REMOTE_ASSET_DIR'"
  remote_copy_file "$ASSET_DIR/bacscloud-logo-transparent.png" "$REMOTE_ASSET_DIR/"
  remote_copy_file "$ASSET_DIR/bacscloud-favicon-transparent.png" "$REMOTE_ASSET_DIR/"
  remote_copy_file "$ASSET_DIR/bacscloud-login-background-safe-2560x1440.png" "$REMOTE_ASSET_DIR/"
  ok "Assets copied to $VM_IP:$REMOTE_ASSET_DIR"
fi

# Build the remote VM script. This runs as root on VM104 through sudo.
REMOTE_SCRIPT="$(cat <<REMOTE_EOF
set -Eeuo pipefail
MODE=$(printf '%q' "$MODE")
REMOTE_ASSET_DIR=$(printf '%q' "$REMOTE_ASSET_DIR")
BRAND_NAME=$(printf '%q' "$BRAND_NAME")
BRAND_SLOGAN=$(printf '%q' "$BRAND_SLOGAN")
BRAND_URL=$(printf '%q' "$BRAND_URL")
BRAND_COLOR=$(printf '%q' "$BRAND_COLOR")
PREFERRED_CONTAINER=$(printf '%q' "$PREFERRED_CONTAINER")

say() { printf '\\n==> %s\\n' "\$*"; }
ok() { printf 'OK: %s\\n' "\$*"; }
warn() { printf 'WARN: %s\\n' "\$*"; }
fail() { printf 'ERROR: %s\\n' "\$*"; exit 1; }

find_container() {
  if docker ps --format '{{.Names}}' | grep -qx "\$PREFERRED_CONTAINER"; then
    printf '%s\\n' "\$PREFERRED_CONTAINER"
    return 0
  fi
  docker ps --format '{{.Names}}' | grep -Ei '(^|[-_])nextcloud($|[-_])|nextcloud' | head -n 1
}

say "Checking VM104 prerequisites"
command -v docker >/dev/null 2>&1 || fail "docker command not found on VM104"
NC_CONTAINER="\$(find_container)"
[[ -n "\$NC_CONTAINER" ]] || fail "Could not find a running Nextcloud container. Preferred: \$PREFERRED_CONTAINER"
ok "Nextcloud container: \$NC_CONTAINER"

docker exec "\$NC_CONTAINER" test -f /var/www/html/occ || fail "occ not found in container \$NC_CONTAINER"

occ() {
  docker exec -u www-data "\$NC_CONTAINER" php /var/www/html/occ "\$@"
}

container_copy_assets() {
  local container_dir="/tmp/bacscloud-nextcloud-branding"
  docker exec "\$NC_CONTAINER" sh -lc "rm -rf '\$container_dir' && mkdir -p '\$container_dir'"
  docker cp "\$REMOTE_ASSET_DIR/bacscloud-logo-transparent.png" "\$NC_CONTAINER:\$container_dir/bacscloud-logo-transparent.png"
  docker cp "\$REMOTE_ASSET_DIR/bacscloud-favicon-transparent.png" "\$NC_CONTAINER:\$container_dir/bacscloud-favicon-transparent.png"
  docker cp "\$REMOTE_ASSET_DIR/bacscloud-login-background-safe-2560x1440.png" "\$NC_CONTAINER:\$container_dir/bacscloud-login-background-safe-2560x1440.png"
  docker exec "\$NC_CONTAINER" sh -lc "test -s '\$container_dir/bacscloud-logo-transparent.png' && test -s '\$container_dir/bacscloud-favicon-transparent.png' && test -s '\$container_dir/bacscloud-login-background-safe-2560x1440.png'"
  printf '%s\\n' "\$container_dir"
}

backup_status() {
  local backup_dir="/opt/homelab/branding/bacscloud-nextcloud/backups/\$(date +%Y%m%d-%H%M%S)"
  mkdir -p "\$backup_dir"
  {
    echo "# BacsCloud Nextcloud theming backup"
    echo "# Created: \$(date -Is)"
    echo "container=\$NC_CONTAINER"
    for key in name slogan url primary_color color cachebuster logoMime logoheaderMime faviconMime backgroundMime; do
      printf '%s=' "\$key"
      occ config:app:get theming "\$key" 2>/dev/null || true
    done
  } > "\$backup_dir/theming-appconfig.txt"
  ok "Backup metadata saved: \$backup_dir/theming-appconfig.txt"
}

apply_branding() {
  say "Applying BacsCloud branding with Nextcloud occ"
  [[ -d "\$REMOTE_ASSET_DIR" ]] || fail "Remote asset directory not found: \$REMOTE_ASSET_DIR"
  backup_status
  local cdir
  cdir="\$(container_copy_assets)"
  ok "Assets copied inside container: \$cdir"

  occ app:enable theming >/dev/null 2>&1 || true
  occ theming:config name "\$BRAND_NAME"
  occ theming:config slogan "\$BRAND_SLOGAN"
  occ theming:config url "\$BRAND_URL"
  occ theming:config primary_color "\$BRAND_COLOR" || occ theming:config color "\$BRAND_COLOR" || true
  occ theming:config logo "\$cdir/bacscloud-logo-transparent.png"
  occ theming:config logoheader "\$cdir/bacscloud-logo-transparent.png" || true
  occ theming:config favicon "\$cdir/bacscloud-favicon-transparent.png"
  occ theming:config background "\$cdir/bacscloud-login-background-safe-2560x1440.png"
  occ config:app:set theming cachebuster --value "\$(date +%s)" >/dev/null 2>&1 || true

  ok "BacsCloud branding applied"
}

show_status() {
  say "Nextcloud status"
  occ status || true
  say "Theming appconfig"
  for key in name slogan url primary_color color cachebuster logoMime logoheaderMime faviconMime backgroundMime; do
    printf '%-18s : ' "\$key"
    occ config:app:get theming "\$key" 2>/dev/null || true
  done
  say "HTTP health check"
  if command -v curl >/dev/null 2>&1; then
    curl -fsS http://127.0.0.1:8080/status.php || true
    printf '\\n'
  else
    warn "curl is not installed on VM104"
  fi
}

restore_default() {
  say "Restoring common Nextcloud default branding values"
  backup_status
  occ theming:config name "Nextcloud" || true
  occ theming:config slogan "a safe home for all your data" || true
  occ theming:config url "https://nextcloud.com" || true
  occ theming:config primary_color "#0082c9" || occ theming:config color "#0082c9" || true

  # Remove common uploaded asset flags from theming app config when present.
  # This avoids editing core files and is enough for a clean newly installed Homelab instance.
  for key in logoMime logoheaderMime faviconMime backgroundMime; do
    occ config:app:delete theming "\$key" >/dev/null 2>&1 || true
  done
  occ config:app:set theming cachebuster --value "\$(date +%s)" >/dev/null 2>&1 || true
  ok "Default-ish Nextcloud branding restored. If browser cache persists, use Ctrl+F5."
}

case "\$MODE" in
  apply) apply_branding; show_status ;;
  status) show_status ;;
  restore-default) restore_default; show_status ;;
esac
REMOTE_EOF
)"

say "Running branding operation on VM104"
remote_sudo_bash "$REMOTE_SCRIPT"

say "Done"
printf 'Open BacsCloud and hard refresh with Ctrl+F5 if the browser cache still shows old assets.\n'
